from dataclasses import dataclass, field
from typing import Literal

@dataclass
class ConversationTurn:
    role: Literal["user", "assistant"]
    content: str
    turn_id: str

@dataclass
class Conversation:
    session_id: str
    turns: list[ConversationTurn] = field(default_factory=list)

    def to_messages(self) -> list[dict]:
        return [{"role": t.role, "content": t.content} for t in self.turns]

    def edit_turn(self, turn_id: str, new_content: str) -> "Conversation":
        """Return a new Conversation with the given turn edited and everything after it removed."""
        idx = next((i for i, t in enumerate(self.turns) if t.turn_id == turn_id), None)
        if idx is None:
            raise ValueError(f"Turn {turn_id!r} not found")
        edited = ConversationTurn(role=self.turns[idx].role, content=new_content, turn_id=turn_id)
        # Drop the edited turn and everything that follows
        return Conversation(session_id=self.session_id, turns=self.turns[:idx] + [edited])

    def undo_last_turn(self) -> "Conversation":
        """Remove the last user+assistant pair."""
        turns = self.turns
        if len(turns) >= 2 and turns[-1].role == "assistant" and turns[-2].role == "user":
            turns = turns[:-2]
        elif turns and turns[-1].role == "user":
            turns = turns[:-1]
        return Conversation(session_id=self.session_id, turns=turns)

    def branch_at(self, turn_id: str) -> "Conversation":
        """Create a new conversation branching from the turn BEFORE turn_id."""
        import uuid
        idx = next((i for i, t in enumerate(self.turns) if t.turn_id == turn_id), None)
        if idx is None:
            raise ValueError(f"Turn {turn_id!r} not found")
        return Conversation(
            session_id=str(uuid.uuid4()),
            turns=list(self.turns[:idx]),   # copy turns up to (not including) the branch point
        )

// EditableUserMessage.tsx - allows inline editing of a sent user message
import { useState } from "react";

export function EditableUserMessage({
  turnId,
  content,
  onEdit,
}: {
  turnId: string;
  content: string;
  onEdit: (turnId: string, newContent: string) => Promise<void>;
}) {
  const [editing, setEditing]   = useState(false);
  const [draft,   setDraft]     = useState(content);
  const [loading, setLoading]   = useState(false);

  const submit = async () => {
    if (!draft.trim() || draft === content) { setEditing(false); return; }
    setLoading(true);
    try {
      await onEdit(turnId, draft.trim());
      setEditing(false);
    } finally {
      setLoading(false);
    }
  };

  if (editing) {
    return (
      <div className="ml-auto max-w-md">
        <textarea
          value={draft}
          onChange={e => setDraft(e.target.value)}
          className="w-full bg-slate-700 text-slate-100 rounded-xl p-3 text-sm
                     border border-indigo-500 outline-none resize-none"
          rows={Math.max(2, draft.split("\n").length)}
          autoFocus
        />
        <div className="flex gap-2 mt-1 justify-end">
          <button onClick={() => setEditing(false)}
                  className="text-xs text-slate-400 hover:text-slate-200">Cancel</button>
          <button onClick={submit} disabled={loading}
                  className="text-xs bg-indigo-600 hover:bg-indigo-500 text-white px-3 py-1 rounded-lg disabled:opacity-50">
            {loading ? "Sending..." : "Send edit"}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="group relative ml-auto max-w-md">
      <div className="bg-indigo-700 text-white rounded-2xl rounded-br-sm px-4 py-3 text-sm">
        {content}
      </div>
      <button
        onClick={() => { setDraft(content); setEditing(true); }}
        className="absolute -bottom-5 right-0 text-xs text-slate-500 hover:text-slate-300
                   opacity-0 group-hover:opacity-100 transition-opacity"
      >
        Edit
      </button>
    </div>
  );
}

// UndoBar.tsx - persistent undo / redo bar in the chat header
import { useState } from "react";

export function UndoBar({
  canUndo,
  onUndo,
  sessionId,
}: {
  canUndo: boolean;
  onUndo: () => Promise<void>;
  sessionId: string;
}) {
  const [loading, setLoading] = useState(false);

  const handleUndo = async () => {
    setLoading(true);
    try { await onUndo(); }
    finally { setLoading(false); }
  };

  if (!canUndo) return null;

  return (
    <div className="flex items-center gap-2 px-4 py-1.5 bg-slate-800 border-b border-slate-700 text-xs">
      <button
        onClick={handleUndo}
        disabled={loading}
        className="flex items-center gap-1 text-slate-400 hover:text-slate-200
                   disabled:opacity-50 transition-colors"
      >
        <span>&#8634;</span>
        {loading ? "Undoing..." : "Undo last turn"}
      </button>
    </div>
  );
}

