// InlineFeedbackChips.tsx - quick correction buttons below the assistant response
const FEEDBACK_OPTIONS = [
  { label: "Too long",          value: "The response was too long. Please be more concise." },
  { label: "Too short",         value: "The response was too brief. Please elaborate." },
  { label: "Wrong format",      value: "The format was wrong. " },
  { label: "Not what I meant",  value: "That was not quite right. " },
  { label: "More examples",     value: "Please add more concrete examples." },
];

export function InlineFeedbackChips({
  onFeedback,
}: {
  onFeedback: (feedbackText: string) => void;
}) {
  const [selected, setSelected] = useState<string | null>(null);
  const [custom,   setCustom]   = useState("");

  const submit = (text: string) => {
    if (!text.trim()) return;
    setSelected(text);
    onFeedback(text);
  };

  if (selected) {
    return <p className="text-xs text-green-400 mt-1">Feedback applied &#10003;</p>;
  }

  return (
    <div className="flex flex-wrap gap-1.5 mt-2">
      {FEEDBACK_OPTIONS.map(o => (
        <button key={o.value} onClick={() => submit(o.value)}
                className="text-xs bg-slate-800 border border-slate-600 text-slate-400
                           hover:border-indigo-500 hover:text-indigo-300 rounded-full px-2.5 py-1
                           transition-colors">
          {o.label}
        </button>
      ))}
      <input
        value={custom}
        onChange={e => setCustom(e.target.value)}
        onKeyDown={e => e.key === "Enter" && submit(custom)}
        placeholder="Custom feedback..."
        className="text-xs bg-slate-800 border border-slate-600 text-slate-300
                   rounded-full px-2.5 py-1 outline-none w-36 focus:border-indigo-500"
      />
    </div>
  );
}

import time
from dataclasses import dataclass

@dataclass
class CorrectionEvent:
    session_id: str
    action: str           # edit | undo | branch | regenerate | feedback
    turn_id: str | None
    feedback_text: str | None
    timestamp: float = 0.0

    def __post_init__(self):
        if not self.timestamp:
            self.timestamp = time.time()

correction_log: list[CorrectionEvent] = []

def log_correction(session_id, action, turn_id=None, feedback=None):
    correction_log.append(CorrectionEvent(
        session_id=session_id, action=action,
        turn_id=turn_id, feedback_text=feedback
    ))

def get_correction_stats() -> dict:
    from collections import Counter
    actions = Counter(e.action for e in correction_log)
    feedbacks = [e.feedback_text for e in correction_log if e.feedback_text]
    return {"total": len(correction_log), "by_action": dict(actions),
            "recent_feedback": feedbacks[-10:]}
